//!
//! SECOND proof, ALONGSIDE `wasm4pm_crate_catalog_proof.rs.tmpl` (never a
//! replacement for it -- both are generated by every `ggen sync run`). That
//! sibling proof hand-transcribes 6 of the 9 `WASM4PM_CRATES` entries'
//! `purpose` values directly into its own template source and deliberately
//! carries no `sparql:` frontmatter key, for a real, disclosed reason (its
//! own header): re-deriving expectations through the SAME query, in the
//! SAME sync execution, that produced the artifact under test would make
//! the test agree with itself by construction. That reasoning is correct
//! for what THAT proof checks -- "does a human's independent reading of
//! `ontology.ttl` agree with the compiled catalog" -- but it leaves a gap:
//! a hand-transcribed array is authored once, directly into
//! `wasm4pm_crate_catalog_proof.rs.tmpl`'s own template source, and never
//! auto-updates from a query -- so it cannot detect the case where
//! `ontology.ttl` changes LATER (a `w4c:purpose`/`rdfs:label` edit, or a
//! `w4c:Crate` individual added/removed) and nobody remembers to hand-edit
//! the sibling template's literal `find(...).purpose` assertions to match.
//!
//! This proof closes that gap by checking a DIFFERENT thing, not the same
//! thing more strictly: whether `src/wasm4pm_crate_catalog.rs`, as it
//! actually sits on disk (and is actually compiled) right now, still
//! agrees with what `w4c:Crate` individuals say RIGHT NOW. It cannot and
//! does not claim to validate "is the ontology itself correct" -- nothing
//! can, that is definitional -- only "has the checked-in generated
//! artifact silently drifted from the ontology since it was last written."
//!
//! ## Why this is not the same tautology the sibling proof's header warns about
//!
//! 1. Asymmetric freshness, not identical-execution self-agreement.
//!    `wasm4pm_crate_catalog.rs.tmpl` writes its output under
//!    `freeze_policy: checksum`: once a consumer hand-edits
//!    `src/wasm4pm_crate_catalog.rs`, further syncs silently skip
//!    regenerating it (protecting the hand edit) rather than erroring --
//!    the const array can legitimately go stale relative to a LATER
//!    `ontology.ttl` edit while `ggen sync run` still exits 0. This
//!    template carries NO `freeze_policy` of its own: its `LIVE_CRATES`
//!    array below is re-baked from a live query against whatever
//!    `ontology.ttl` says at the moment THIS file is (re)generated. So the
//!    two sides of every assertion below are not guaranteed to come from
//!    the same sync execution -- one (`WASM4PM_CRATES`, via `#[path]`
//!    include of the compiled module) is whatever was last actually
//!    written to disk, frozen or not; the other (`LIVE_CRATES`) is always
//!    "right now." A hand-transcribed expectation frozen at authoring time
//!    cannot distinguish those two states from each other; this one can,
//!    and fails loudly when they diverge.
//! 2. Independent rendering, not the same substitution checked twice. This
//!    template's own for-loop over the `crates` SPARQL result is a
//!    SEPARATE Tera render pass from `wasm4pm_crate_catalog.rs.tmpl`'s own
//!    identical-looking loop over the identical query. A field-mapping bug
//!    local to ONE of the two templates (wrong variable, dropped row,
//!    stray escaping) produces a generated-array value that this proof's
//!    independently-rendered `LIVE_CRATES` will not match, and the
//!    assertions below fail -- mirroring the same "two independent
//!    renderings checked against each other" principle
//!    `refusal_taxonomy_sparql_derived_proof.rs.tmpl` (praxis-core-pack)
//!    established as this program's reference pattern.
//!
//! ## Honest scope
//!
//! Unlike praxis-core-pack/star-toml-pack/lsp-max-pack's SPARQL-derived
//! proofs (which compare against non-Rust generated text via
//! `include_str!`/substring search, since their artifacts are TOML/
//! Markdown/JSON), `wasm4pm_crate_catalog.rs.tmpl`'s artifact IS Rust
//! source -- so this proof `#[path]`-includes the real compiled module and
//! compares `Wasm4pmCrate` struct values directly via `assert_eq!`, the
//! same mechanism the sibling hand-transcribed proof already uses. This is
//! a strictly stronger comparison than text search (it goes through the
//! type system, not string matching) but it inherits the same limits: it
//! cannot prove ggen's own SPARQL/Tera pipeline is bug-free in some
//! absolute sense -- only that, on the sync run that (re)generated this
//! file, the live ontology and the checked-in generated artifact said the
//! same thing. It does not attempt `wasm4pm_crate_deps.rs`/`CRATE_DEPS`
//! fidelity -- that is `wasm4pm_crate_deps_proof.rs.tmpl`'s job (hand-
//! transcribed only, still open); duplicating it here would be scope
//! creep, not a second check.

#[path = "../src/wasm4pm_crate_catalog.rs"]
mod wasm4pm_crate_catalog;

use wasm4pm_crate_catalog::{Wasm4pmCrate, WASM4PM_CRATES};

/// Every `w4c:Crate` individual as of the sync run that generated THIS
/// file, freshly baked from the `crates` SPARQL result -- never hand-typed.
const LIVE_CRATES: &[Wasm4pmCrate] = &[
    Wasm4pmCrate { name: "bench-tools", purpose: "Benchmark tools for the wasm4pm workspace." },
    Wasm4pmCrate { name: "miniml", purpose: "A minimal, blazing-fast WASM-powered machine learning library with SIMD acceleration." },
    Wasm4pmCrate { name: "ocpq", purpose: "Object-centric process querying & constraints (binding boxes, query trees, E2O/O2O/TBE predicates, CHILD SET) per Kuesters & van der Aalst 2025." },
    Wasm4pmCrate { name: "prolog8", purpose: "Byte-capped proof engine for policy, workflow, and agent action admission." },
    Wasm4pmCrate { name: "tps-metrics", purpose: "Toyota Production System metrics collection and analysis." },
    Wasm4pmCrate { name: "wasm4pm", purpose: "High-performance process mining algorithms in WebAssembly for JavaScript/TypeScript." },
    Wasm4pmCrate { name: "wasm4pm-cli", purpose: "The official wasm4pm process mining command-line interface." },
    Wasm4pmCrate { name: "wasm4pm-cognition", purpose: "AutoSystems old-AI cognition kernel: frames, production rules, Prolog, STRIPS, Hearsay-II blackboard, BLAKE3 receipt chain, adversarial gates." },
    Wasm4pmCrate { name: "wasm4pm-planner", purpose: "wasm4pm-native PDDL-subset temporal planner with prolog8 admission gating and an MCP server -- a fresh design drawing on bcinr-pddl's durative-action scheduler and capability-router pattern." },
];

/// Floor sanity check: guards against a silently-broken or silently-empty
/// SPARQL query (e.g. a query engine regression, a typo in the query text
/// that still parses but matches nothing) making every assertion below
/// vacuously true. If this fails, the failure is in the query itself, not
/// in drift between the ontology and the generated catalog.
#[test]
fn sparql_query_returned_at_least_one_crate() {
    assert!(
        !LIVE_CRATES.is_empty(),
        "the `crates` SPARQL query against ontology.ttl returned zero w4c:Crate rows -- \
         either the ontology lost every individual or the query itself is broken; every \
         other assertion in this file would otherwise pass vacuously"
    );
}

/// Row-count parity between what the live ontology says right now and what
/// is actually compiled into `WASM4PM_CRATES` right now.
#[test]
fn crate_count_matches_generated_catalog_right_now() {
    assert_eq!(
        LIVE_CRATES.len(),
        WASM4PM_CRATES.len(),
        "ontology.ttl has {} w4c:Crate individuals right now, but the checked-in \
         src/wasm4pm_crate_catalog.rs has {} WASM4PM_CRATES entries -- the generated \
         catalog has drifted behind ontology.ttl",
        LIVE_CRATES.len(),
        WASM4PM_CRATES.len()
    );
}

/// The core check: every crate the live ontology reports right now is
/// still reflected, field-for-field, in the artifact as it actually sits
/// on disk (and is actually compiled) right now. Failing here means the
/// checked-in generated catalog no longer matches ontology.ttl -- exactly
/// the silent-drift failure mode cap05's obligation text names, and
/// neither the hand-transcribed proof (which never re-reads ontology.ttl
/// after `wasm4pm_crate_catalog_proof.rs.tmpl` was last hand-edited) nor a
/// plain `diff` against a stale copy would catch it.
#[test]
fn catalog_matches_live_ontology_row_for_row() {
    for (i, (live, generated)) in LIVE_CRATES.iter().zip(WASM4PM_CRATES.iter()).enumerate() {
        assert_eq!(
            live.name, generated.name,
            "row {i}: live ontology says name `{}` but generated WASM4PM_CRATES[{i}].name \
             is `{}` -- drift detected",
            live.name, generated.name
        );
        assert_eq!(
            live.purpose, generated.purpose,
            "live ontology says {} has purpose `{}` but generated \
             WASM4PM_CRATES[{i}].purpose is `{}` -- drift detected",
            live.name, live.purpose, generated.purpose
        );
    }
    // Whole-array equality as a single, unambiguous final check: catches a
    // length mismatch class this zip-based loop alone could miss (zip
    // stops at the shorter side), on top of `crate_count_matches_generated_catalog_right_now`.
    assert_eq!(
        LIVE_CRATES, WASM4PM_CRATES,
        "LIVE_CRATES (freshly derived from ontology.ttl this sync) does not equal \
         WASM4PM_CRATES (the checked-in generated catalog) -- generated catalog has \
         drifted behind ontology.ttl"
    );
}

/// `ORDER BY ?label` in the live query is expected to sort lexically
/// ascending. This is a live regression guard on the query engine's own
/// collation (praxis-graphlaw or oxigraph, whichever backend answered this
/// sync), not a hand-asserted fact about how the array happens to be
/// typed -- if the engine's ORDER BY collation ever changes, this fails on
/// the very next sync instead of silently reordering the generated
/// catalog and having nothing notice (the sibling hand-transcribed proof's
/// own `catalog_is_sorted_by_name` only checks the compiled array against
/// itself, not against a freshly re-queried order).
#[test]
fn live_row_order_is_lexical_ascending_by_label() {
    let names: Vec<&str> = LIVE_CRATES.iter().map(|c| c.name).collect();
    let mut sorted_names = names.clone();
    sorted_names.sort_unstable();
    assert_eq!(
        names, sorted_names,
        "LIVE_CRATES is not in lexically-ascending name order -- the query's own \
         `ORDER BY ?label` did not produce sorted results this sync"
    );
}

/// Negative sanity check: a fabricated crate name that does not exist in
/// `ontology.ttl` must not spuriously appear in the live-derived array.
/// Guards against a naive query/loop silently matching everything.
#[test]
fn live_ontology_rejects_unknown_crate_name() {
    let bogus = "wasm4pm-not-a-real-crate";
    assert!(
        !LIVE_CRATES.iter().any(|c| c.name == bogus),
        "sanity: bogus crate name must not appear in LIVE_CRATES"
    );
    assert!(
        !WASM4PM_CRATES.iter().any(|c| c.name == bogus),
        "sanity: bogus crate name must not appear in generated WASM4PM_CRATES either"
    );
}
